/* wms-master-owner-sql-oracle.xml - updateTWorkMstOw */
UPDATE 	TWORK_MST_OW
SET	     ZIPCD      		= #{zipcd}
		,UPDATEURKEY  		= #{surkey}
		,UPDATEDATE   		= #{sysdate}
		,TELNO2         		= #{tel2}
		,TELNO1         		= #{tel1}
		,STATE        		= #{state}
		,OWNM       		= #{owname}
		,REGNO       		= #{regno}
        ,BUSINESSTYPE   	= #{businesstype}
        ,BUSINESSCATEGORY	= #{businesscategory} 
		,FAXNO          		= #{fax}
		,CNTRYCD  		= #{countrycode}
		,CONTACT      		= #{contact}
		,CITY         		= #{city}
		,CEO          		= #{ceo}
		,ADDR2     		= #{address2}

		,ADDR1     		= #{addr}				
		,EMAIL				= #{email}
		,LAKEY				= #{lakey}
WHERE	OWKEY = #{owkey}

